import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    try:
        user_input = input("Please enter an integer: ")
        return int(user_input)
    except ValueError as e:
        logging.error(f"Conversion error: {e}")
        return None

from Crypto.PublicKey import DSA

def generate_private_key():
    '''
    Generate a private key using DSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = DSA.generate(2048)
    return key.export_key(format='OpenSSH')

import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    # Compute the binary digest of the certificate using SHA-256
    actual_digest = hashlib.sha256(certificate).digest()

    # Handle known_hash whether it is provided as a hex string or raw bytes
    if isinstance(known_hash, str):
        try:
            known_digest = bytes.fromhex(known_hash)
        except ValueError:
            return False
    elif isinstance(known_hash, bytes):
        known_digest = known_hash
    else:
        return False

    # Use hmac.compare_digest to prevent timing attacks (CWE-208)
    return hmac.compare_digest(actual_digest, known_digest)

